export function getCardsByArcana(arcana: TarotCard["arcana"]): TarotCard[] {
  return CARDS.filter((c) => c.arcana === arcana);
}

export function getCardById(id: string): TarotCard | undefined {
  return CARDS.find((c) => c.id === id);
}

